// Belirli bir harf için rastgele soru seçici helper
export function getPassaparolaQuestionForLetter(letter: string): AZQuestion {
  const upper = letter.toUpperCase();
  const list = PASSAPAROLA_QUESTIONS_DB[upper] || [];
  if (list.length > 0) {
    const idx = Math.floor(Math.random() * list.length);
    return list[idx];
  }
  // Eğer o harfe soru tanımlanmamışsa geçici şablon döndürür
  return {
    letter: upper,
    question: `"${upper}" harfi için soru henüz eklenmemiştir.`,
    answer: "Örnek",
    clues: []
  };
}
